#!/usr/bin/env node

const { execSync } = require('child_process');
const path = require('path');

// --- Configuration ---
const APP_NAME = 'my-node-app'; // Your application's name
const BUILD_DIR = 'dist';     // Directory where your build artifacts are placed (e.g., 'dist', 'build', 'public')

// Deployment target configuration - use environment variables for sensitive data
const DEPLOY_USER = process.env.PROD_USER || 'deployuser';
const DEPLOY_HOST = process.env.PROD_HOST || 'your-production-server.com';
const DEPLOY_PATH = process.env.PROD_PATH || `/var/www/${APP_NAME}`;
const DEPLOY_SSH_KEY = process.env.PROD_SSH_KEY_PATH || '~/.ssh/id_rsa'; // Path to private SSH key for deployment

// --- Helper Functions ---

/**
 * Runs a shell command synchronously and logs its output.
 * Throws an error if the command fails, causing the script to exit.
 * @param {string} command The shell command to execute.
 * @param {object} options Options for execSync (e.g., { cwd: '...' }).
 */
function runCommand(command, options = {}) {
    console.log(`\n--- Executing: ${command} ---`);
    try {
        execSync(command, { stdio: 'inherit', ...options });
        console.log(`--- Command Succeeded ---`);
    } catch (error) {
        console.error(`\n--- Command Failed: ${command} ---`);
        console.error(error.message);
        process.exit(1); // Exit with a non-zero code to indicate failure
    }
}

/**
 * Checks if a specific command-line utility exists on the system.
 * @param {string} command The utility name (e.g., 'rsync', 'docker').
 * @returns {boolean} True if the command exists, false otherwise.
 */
function commandExists(command) {
    try {
        execSync(`command -v ${command}`, { stdio: 'pipe' });
        return true;
    } catch (e) {
        return false;
    }
}

// --- CI/CD Pipeline Steps ---

/**
 * Installs Node.js dependencies. Uses 'npm ci' for speed and reliability in CI environments.
 * Requires a 'package-lock.json' (or 'npm-shrinkwrap.json') file to be present.
 */
function installDependencies() {
    console.log('\n--- Step 1: Installing Dependencies ---');
    // '--prefer-offline': Attempts to use cached packages first.
    // '--no-audit': Skips the security audit for faster installation (consider implications).
    runCommand('npm ci --prefer-offline --no-audit');
}

/**
 * Runs the application's test suite.
 * Assumes a 'test' script is defined in 'package.json'.
 */
function runTests() {
    console.log('\n--- Step 2: Running Tests ---');
    runCommand('npm test');
}

/**
 * Builds the application for production.
 * Assumes a 'build' script is defined in 'package.json' that outputs to `BUILD_DIR`.
 */
function buildApplication() {
    console.log('\n--- Step 3: Building Application ---');
    runCommand('npm run build');

    // Verify that the build output directory exists
    const buildPath = path.join(process.cwd(), BUILD_DIR);
    console.log(`Verifying build output directory: ${buildPath}`);
    try {
        execSync(`test -d ${buildPath}`);
        console.log(`Build directory '${BUILD_DIR}' found.`);
    } catch (error) {
        console.error(`Error: Build directory '${BUILD_DIR}' not found. Build might have failed or output to a different location.`);
        process.exit(1);
    }
}

/**
 * Deploys the built application to the production server using rsync over SSH.
 * This is a common method for simple server deployments.
 * For more complex setups (e.g., Docker, Kubernetes, Serverless), this step would be replaced.
 */
function deployToProduction() {
    console.log('\n--- Step 4: Deploying to Production ---');

    if (!commandExists('rsync')) {
        console.error('Error: rsync command not found. Please install rsync for deployment (e.g., `sudo apt-get install rsync`).');
        process.exit(1);
    }

    console.log(`Deploying '${BUILD_DIR}/' to ${DEPLOY_USER}@${DEPLOY_HOST}:${DEPLOY_PATH}`);

    // 1. Ensure the remote deployment directory exists
    runCommand(`ssh -i ${DEPLOY_SSH_KEY} ${DEPLOY_USER}@${DEPLOY_HOST} "mkdir -p ${DEPLOY_PATH}"`);

    // 2. Use rsync to transfer files efficiently
    // -a: archive mode (preserves permissions, timestamps, etc.)
    // -v: verbose output
    // -z: compress file data during transfer
    // --delete: delete extraneous files from the destination directory (ensures a clean deployment)
    // -e "ssh -i ...": specifies the SSH command with the private key for authentication
    // --exclude: prevents certain files/directories from being copied
    const rsyncCommand = `rsync -avz --delete --exclude 'node_modules' --exclude '.git' -e "ssh -i ${DEPLOY_SSH_KEY}" ${BUILD_DIR}/ ${DEPLOY_USER}@${DEPLOY_HOST}:${DEPLOY_PATH}`;
    runCommand(rsyncCommand);

    console.log('\n--- Deployment Complete! ---');
    console.log(`Application deployed to: ssh ${DEPLOY_USER}@${DEPLOY_HOST}`);
    console.log(`Remote path: ${DEPLOY_PATH}`);

    // Optional: Restart the application service on the remote server
    // This command is highly dependent on your server setup (e.g., systemd, PM2, Docker Compose).
    // Uncomment and modify if applicable to your environment.
    // console.log('\n--- Restarting remote application service ---');
    // runCommand(`ssh -i ${DEPLOY_SSH_KEY} ${DEPLOY_USER}@${DEPLOY_HOST} "sudo systemctl restart ${APP_NAME}"`);
    // console.log('Remote application service restarted.');
}

// --- Main Pipeline Execution ---

/**
 * Orchestrates the entire CI/CD pipeline.
 */
async function pipeline() {
    console.log(`\n--- Starting CI/CD Pipeline for ${APP_NAME} ---`);

    try {
        installDependencies();
        runTests();
        buildApplication();
        deployToProduction();

        console.log('\n--- CI/CD Pipeline Succeeded! ---');
        process.exit(0); // Exit successfully
    } catch (error) {
        // Errors are already handled by runCommand, this catch block is mostly for top-level unexpected errors.
        console.error('\n--- CI/CD Pipeline Failed! ---');
        console.error(error);
        process.exit(1); // Exit with failure
    }
}

// Execute the pipeline
pipeline();